using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // HasIndex removed: Cosmos DB provider now throws at startup.
        // Manage indexing via Azure Portal, Bicep, or Terraform instead.

        modelBuilder.Entity<Blog>(b =>
        {
            // Keep legacy "Discriminator" property name (EF9 defaults to "$type")
            b.HasDiscriminator<string>("Discriminator");

            // Keep legacy id format "Blog|1" (EF9 defaults to key-only "1")
            b.HasRootDiscriminatorInJsonId(true);
        });
    }
}
